from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict

def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    # Initialize dictionary to store aggregated results
    aggregated_data = defaultdict(lambda: {
        "count": 0,
        "sum_score": 0.0,
        "max_score": float('-inf'),
        "min_score": float('inf')
    })

    # Iterate through each SearchResult
    for result in search_results:
        # Extract metadata value for group_by_field
        group_value = result.metadata.get(group_by_field)

        # Handle missing grouping field values
        if group_value is None:
            group_value = 'unknown'

        # Get the group's statistics dictionary
        stats = aggregated_data[group_value]

        # Update count
        stats["count"] += 1

        # Update sum_score
        stats["sum_score"] += result.score

        # Update max_score
        if result.score > stats["max_score"]:
            stats["max_score"] = result.score

        # Update min_score
        if result.score < stats["min_score"]:
            stats["min_score"] = result.score

    # Calculate average score for each group
    for group_value, stats in aggregated_data.items():
        if stats["count"] > 0:
            stats["avg_score"] = stats["sum_score"] / stats["count"]
        else:
            stats["avg_score"] = 0.0

    # Apply custom aggregation functions if provided
    if aggregation_funcs:
        for group_value, stats in aggregated_data.items():
            for field_name, func in aggregation_funcs.items():
                # Get all values for the field in this group
                values = []
                for result in search_results:
                    # Check if we're aggregating on a metadata field or top-level field
                    if field_name in ['id', 'score', 'text']:
                        value = getattr(result, field_name)
                    else:
                        value = result.metadata.get(field_name)

                    if value is not None:
                        values.append(value)

                # Apply the aggregation function
                try:
                    result_value = func(values)
                    stats[field_name] = result_value
                except Exception as e:
                    # Handle potential errors in aggregation functions
                    stats[field_name] = None

    # Convert defaultdict to regular dict for cleaner output
    final_result = {}
    for group_value, stats in aggregated_data.items():
        final_result[group_value] = stats

    return final_result

